1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
7	const LOYALTY_DISCOUNT_RATE = 0.2;
8	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
20	type QuoteStep = { op: "quote"; items: Item[] };
21	type Customer = { yearsWithMHPCO: number };
22	type Scenario = { customer: Customer; steps: [QuoteStep] };
23	
24	const quoteResult = (premium: number) => ({ results: [{ premium }] });
25	
26	const sum = (numbers: number[]): number =>
27	  numbers.reduce((total, n) => total + n, 0);
28	
29	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
30	
31	const isBlockOfThreeAlike = (items: Item[]): boolean =>
32	  items.length === 3 && items.every((item) => item.type === items[0].type);
33	
34	const groupByType = (items: Item[]): Item[][] => {
35	  const groups: Record<string, Item[]> = {};
36	  for (const item of items) {
37	    (groups[item.type] ||= []).push(item);
38	  }
39	  return Object.values(groups);
40	};
41	
42	const groupBasePremium = (group: Item[]): number =>
43	  isBlockOfThreeAlike(group)
44	    ? BLOCK_OF_THREE_BASE_PREMIUM
45	    : sum(group.map(itemBasePremium));
46	
47	const itemsBasePremium = (items: Item[]): number =>
48	  sum(groupByType(items).map(groupBasePremium));
49	
50	const conditionalSurcharge = (item: Item, applies: boolean, rate: number): number =>
51	  applies ? itemBasePremium(item) * rate : 0;
52	
53	const cursedSurcharge = (item: Item): number =>
54	  conditionalSurcharge(item, item.cursed === true, CURSED_SURCHARGE_RATE);
55	
56	const highEnchantmentSurcharge = (item: Item): number =>
57	  conditionalSurcharge(
58	    item,
59	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
60	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
61	  );
62	
63	const itemSurchargesTotal = (items: Item[]): number =>
64	  sum(items.map((item) => cursedSurcharge(item) + highEnchantmentSurcharge(item)));
65	
66	const firstInsuranceSurcharge = (amount: number): number =>
67	  amount * FIRST_INSURANCE_SURCHARGE_RATE;
68	
69	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
70	  customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
71	    ? basePremium * LOYALTY_DISCOUNT_RATE
72	    : 0;
73	
74	const quotePremiumFor = (items: Item[], customer: Customer): number => {
75	  const policyBase = itemsBasePremium(items);
76	  return Math.ceil(
77	    policyBase +
78	      itemSurchargesTotal(items) +
79	      firstInsuranceSurcharge(policyBase) -
80	      loyaltyDiscount(policyBase, customer) +
81	      PROCESSING_FEE,
82	  );
83	};
84	
85	export const runScenario = (input: Scenario): unknown =>
86	  quoteResult(quotePremiumFor(input.steps[0].items, input.customer));
